+        type: 'user_welcome',
+        subject: 'Welcome to TaskFlow Pro!',
+        body: 'Hi Alice, welcome to TaskFlow Pro.',
+        metadata: { userId: 'user-1' },
+      });
+
+      const result = await adapter.send(payload);
+      expect(result.success).toBe(true);
+
+      const deliveries = adapter.getDeliveries();
+      const body = JSON.parse(deliveries[0]!.body);
+      expect(body.type).toBe('user_welcome');
+      expect(body.body).toBe('Hi Alice, welcome to TaskFlow Pro.');
+    });
+
+    it('should include secret header when configured', async () => {
+      const secretAdapter = new WebhookAdapter(
+        { url: 'https://example.com/webhook', secret: 'my-secret-token' },
+        transport,
+      );
+
+      await secretAdapter.send(makePayload());
+
+      const deliveries = transport.getSentDeliveries();
+      expect(deliveries[0]!.headers['X-Webhook-Secret']).toBe('my-secret-token');
+    });
