/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements NotificationAdapter interface with:
 * - JSON payload formatting: structures notification data as JSON
 * - HTTP POST delivery: sends payload to a configured webhook URL
 * - Transport abstraction: pluggable HTTP transport for testing
 *
 * In production, the transport layer would use fetch or an HTTP client library.
 * The default transport uses fetch. An in-memory transport is provided for testing.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  url: string;
  secret?: string;
  headers?: Record<string, string>;
}

/**
 * The JSON payload sent to webhook endpoints.
 */
export interface WebhookDelivery {
  url: string;
  headers: Record<string, string>;
  body: string;
}

/**
 * Webhook transport interface — abstracts the actual HTTP request.
 * Swap this out for fetch, axios, etc. in production.
 */
export interface WebhookTransport {
  post(delivery: WebhookDelivery): Promise<{ statusCode: number }>;
}

/**
 * In-memory webhook transport for testing and development.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private sent: WebhookDelivery[] = [];

  async post(delivery: WebhookDelivery): Promise<{ statusCode: number }> {
    this.sent.push(delivery);
    return { statusCode: 200 };
  }

  getSentDeliveries(): WebhookDelivery[] {
    return [...this.sent];
  }

  clearSentDeliveries(): void {
    this.sent = [];
  }
}

/**
 * Format a notification payload as a JSON webhook body.
 */
function formatPayload(payload: NotificationPayload): string {
  return JSON.stringify({
    id: payload.id,
    type: payload.type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    metadata: payload.metadata,
    createdAt: payload.createdAt.toISOString(),
  });
}

/**
 * Validate a webhook URL. Returns the trimmed URL or null if invalid.
 */
export function resolveWebhookUrl(url: string): string | null {
  const trimmed = url.trim();
  if (!trimmed) {
    return null;
  }
  try {
    const parsed = new URL(trimmed);
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return null;
    }
    return trimmed;
  } catch {
    return null;
  }
}

// --- Adapter implementation ---

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private config: WebhookConfig;

  // Stores raw payloads for testing
  private sentPayloads: NotificationPayload[] = [];

  constructor(config: WebhookConfig, transport?: WebhookTransport) {
    this.config = { ...config };
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a webhook notification.
   *
   * 1. Validates the configured webhook URL
   * 2. Formats the notification payload as JSON
   * 3. POSTs it via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending webhook for ${payload.type} to ${this.config.url}`,
    );

    try {
      // 1. Validate URL
      const resolvedUrl = resolveWebhookUrl(this.config.url);
      if (!resolvedUrl) {
        this.logger.error(`Invalid webhook URL: ${this.config.url}`);
        return {
          success: false,
          channel: 'webhook',
          recipient: payload.recipient,
          error: `Invalid webhook URL: ${this.config.url}`,
        };
      }

      // 2. Format payload
      const body = formatPayload(payload);

      // 3. Build headers
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
        ...this.config.headers,
      };

      if (this.config.secret) {
        headers['X-Webhook-Secret'] = this.config.secret;
      }

      // 4. Deliver via transport
      const delivery: WebhookDelivery = { url: resolvedUrl, headers, body };
      const result = await this.transport.post(delivery);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.sentPayloads.push(payload);

        this.logger.info(
          `Webhook delivered to ${resolvedUrl} (status: ${result.statusCode})`,
        );

        return {
          success: true,
          channel: 'webhook',
          recipient: payload.recipient,
          deliveredAt: new Date(),
        };
      }

      this.logger.error(
        `Webhook delivery failed with status ${result.statusCode}`,
      );
      return {
        success: false,
        channel: 'webhook',
        recipient: payload.recipient,
        error: `Webhook returned status ${result.statusCode}`,
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Webhook delivery failed: ${message}`);

      return {
        success: false,
        channel: 'webhook',
        recipient: payload.recipient,
        error: message,
      };
    }
  }

  /**
   * Get all sent notification payloads. Useful for testing.
   */
  getSentPayloads(): NotificationPayload[] {
    return [...this.sentPayloads];
  }

  /**
   * Get all webhook deliveries from the transport (if using InMemoryWebhookTransport).
   */
  getDeliveries(): WebhookDelivery[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getSentDeliveries();
    }
    return [];
  }

  /**
   * Clear sent payloads and deliveries. Useful for testing.
   */
  clearSentPayloads(): void {
    this.sentPayloads = [];
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clearSentDeliveries();
    }
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<WebhookConfig> {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
  resolveWebhookUrl,
} from '../../src/adapters/webhook.adapter.js';
import type {
  WebhookDelivery,
  WebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'webhook',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-15T10:00:00.000Z'),
    ...overrides,
  };
}

describe('resolveWebhookUrl', () => {
  it('should accept valid http URLs', () => {
    expect(resolveWebhookUrl('http://example.com/webhook')).toBe('http://example.com/webhook');
  });

  it('should accept valid https URLs', () => {
    expect(resolveWebhookUrl('https://example.com/webhook')).toBe('https://example.com/webhook');
  });

  it('should trim whitespace', () => {
    expect(resolveWebhookUrl('  https://example.com/webhook  ')).toBe('https://example.com/webhook');
  });

  it('should reject empty strings', () => {
    expect(resolveWebhookUrl('')).toBeNull();
    expect(resolveWebhookUrl('   ')).toBeNull();
  });

  it('should reject non-http protocols', () => {
    expect(resolveWebhookUrl('ftp://example.com/webhook')).toBeNull();
    expect(resolveWebhookUrl('file:///etc/passwd')).toBeNull();
  });

  it('should reject invalid URLs', () => {
    expect(resolveWebhookUrl('not-a-url')).toBeNull();
    expect(resolveWebhookUrl('://missing-protocol')).toBeNull();
  });
});

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter(
      { url: 'https://example.com/webhook' },
      transport,
    );
  });

  it('should have channel set to webhook', () => {
    expect(adapter.channel).toBe('webhook');
  });

  describe('send', () => {
    it('should POST notification payload as JSON', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.recipient).toBe('alice@example.com');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]!.url).toBe('https://example.com/webhook');
      expect(deliveries[0]!.headers['Content-Type']).toBe('application/json');

      const body = JSON.parse(deliveries[0]!.body);
      expect(body.id).toBe('notif-0001');
      expect(body.type).toBe('order_confirmation');
      expect(body.recipient).toBe('alice@example.com');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
      expect(body.createdAt).toBe('2026-01-15T10:00:00.000Z');
    });

    it('should send order status update payload', async () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to shipped.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'shipped' },
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);

      const deliveries = adapter.getDeliveries();
      const body = JSON.parse(deliveries[0]!.body);
      expect(body.type).toBe('order_status_update');
      expect(body.metadata.newStatus).toBe('shipped');
    });

    it('should send welcome notification payload', async () => {
      const payload = makePayload({
        type: 'user_welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, welcome to TaskFlow Pro.',
        metadata: { userId: 'user-1' },
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);

      const deliveries = adapter.getDeliveries();
      const body = JSON.parse(deliveries[0]!.body);
      expect(body.type).toBe('user_welcome');
      expect(body.body).toBe('Hi Alice, welcome to TaskFlow Pro.');
    });

    it('should include secret header when configured', async () => {
      const secretAdapter = new WebhookAdapter(
        { url: 'https://example.com/webhook', secret: 'my-secret-token' },
        transport,
      );

      await secretAdapter.send(makePayload());

      const deliveries = transport.getSentDeliveries();
      expect(deliveries[0]!.headers['X-Webhook-Secret']).toBe('my-secret-token');
    });

    it('should include custom headers when configured', async () => {
      const customAdapter = new WebhookAdapter(
        {
          url: 'https://example.com/webhook',
          headers: { 'X-Custom-Header': 'custom-value' },
        },
        transport,
      );

      await customAdapter.send(makePayload());

      const deliveries = transport.getSentDeliveries();
      expect(deliveries[0]!.headers['X-Custom-Header']).toBe('custom-value');
      expect(deliveries[0]!.headers['Content-Type']).toBe('application/json');
    });

    it('should fail for invalid webhook URL', async () => {
      const badAdapter = new WebhookAdapter(
        { url: 'not-a-url' },
        transport,
      );

      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(badAdapter.getSentPayloads()).toHaveLength(0);
      expect(transport.getSentDeliveries()).toHaveLength(0);
    });

    it('should fail for non-2xx status codes', async () => {
      const failTransport: WebhookTransport = {
        post: async () => ({ statusCode: 500 }),
      };
      const failAdapter = new WebhookAdapter(
        { url: 'https://example.com/webhook' },
        failTransport,
      );

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('status 500');
    });

    it('should handle transport errors gracefully', async () => {
      const errorTransport: WebhookTransport = {
        post: async () => {
          throw new Error('Connection refused');
        },
      };
      const errorAdapter = new WebhookAdapter(
        { url: 'https://example.com/webhook' },
        errorTransport,
      );

      const result = await errorAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should track sent payloads', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentPayloads();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.recipient).toBe('alice@example.com');
    });

    it('should not track payload on failure', async () => {
      const failTransport: WebhookTransport = {
        post: async () => ({ statusCode: 503 }),
      };
      const failAdapter = new WebhookAdapter(
        { url: 'https://example.com/webhook' },
        failTransport,
      );

      await failAdapter.send(makePayload());
      expect(failAdapter.getSentPayloads()).toHaveLength(0);
    });

    it('should include metadata in JSON body', async () => {
      const payload = makePayload({
        metadata: { orderId: 'order-42', userId: 'user-7', custom: 'data' },
      });

      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      const body = JSON.parse(deliveries[0]!.body);
      expect(body.metadata).toEqual({ orderId: 'order-42', userId: 'user-7', custom: 'data' });
    });
  });

  describe('clearSentPayloads', () => {
    it('should clear both payload and delivery stores', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentPayloads()).toHaveLength(1);
      expect(adapter.getDeliveries()).toHaveLength(1);

      adapter.clearSentPayloads();
      expect(adapter.getSentPayloads()).toHaveLength(0);
      expect(adapter.getDeliveries()).toHaveLength(0);
    });
  });

  describe('getConfig', () => {
    it('should return current configuration', () => {
      const config = adapter.getConfig();
      expect(config.url).toBe('https://example.com/webhook');
    });

    it('should return a copy (not mutable reference)', () => {
      const config = adapter.getConfig();
      (config as Record<string, unknown>).url = 'https://evil.com/hook';
      expect(adapter.getConfig().url).toBe('https://example.com/webhook');
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  it('should store and retrieve sent deliveries', async () => {
    const transport = new InMemoryWebhookTransport();
    const delivery: WebhookDelivery = {
      url: 'https://example.com/webhook',
      headers: { 'Content-Type': 'application/json' },
