    expect(transport.getSentDeliveries()[0]!.url).toBe('https://example.com/webhook');
  });

  it('should clear sent deliveries', async () => {
    const transport = new InMemoryWebhookTransport();
    await transport.post({
      url: 'https://example.com/webhook',
      headers: {},
      body: '{}',
    });

    transport.clearSentDeliveries();
    expect(transport.getSentDeliveries()).toHaveLength(0);
  });
});

